abstract class SearchEvent{} class SearchSubmitted extends SearchEvent{ final String query; SearchSubmitted(this.query); }
abstract class SearchState{} class SearchInitial extends SearchState{} class SearchLoading extends SearchState{} class SearchLoaded extends SearchState{ final List<String> results; SearchLoaded(this.results); } class SearchError extends SearchState{ final String message; SearchError(this.message); }
class SearchBloc extends Bloc<SearchEvent, SearchState> { SearchBloc() : super(SearchInitial());
@override Stream<SearchState> mapEventToState(SearchEvent event) async* { if(event is SearchSubmitted){ yield SearchLoading(); try { final results = await searchApi(event.query); yield SearchLoaded(results); } catch(e){ yield SearchError(e.toString()); } } } }
